function hashCallWithReplayProtection(
    Payload.Decoded calldata payload,
    uint256 callIdx
) public view returns (bytes32 callHash) {
    return keccak256(
        abi.encodePacked(
            payload.noChainId ? 0 : block.chainid,
            payload.space,
            payload.nonce,
            callIdx,
            Payload.hashCall(payload.calls[callIdx])
        )
    );
}
